```{.r .cell-code}
library(tidyverse)
library(fixest)
library(modelsummary)
library(flextable)

wms <- read_csv("data/wms_da_textbook.csv", show_col_types = FALSE) |>
  mutate(log_emp = log(emp_firm))
```
